var FindSumPairs = function(nums1, nums2) {
    this.nums2 = nums2.slice();
    this.cnt1 = new Map();
    for (const v of nums1) this.cnt1.set(v, (this.cnt1.get(v) || 0) + 1);
    this.cnt2 = new Map();
    for (const v of nums2) this.cnt2.set(v, (this.cnt2.get(v) || 0) + 1);
};
FindSumPairs.prototype.add = function(index, val) {
    const old = this.nums2[index];
    this.cnt2.set(old, this.cnt2.get(old) - 1);
    const nv = old + val;
    this.nums2[index] = nv;
    this.cnt2.set(nv, (this.cnt2.get(nv) || 0) + 1);
};
FindSumPairs.prototype.count = function(tot) {
    let total = 0;
    for (const [v, c] of this.cnt2.entries()) {
        if (c === 0) continue;
        const need = tot - v;
        if (this.cnt1.has(need)) total += c * this.cnt1.get(need);
    }
    return total;
};
